#include "reveal.h"
int ciced(const char*cmd){char tc[256];strncpy(tc,cmd,sizeof(tc)-1);tc[sizeof(tc)-1]='\0';char*e=tc+strlen(tc)-1;while(e>tc&&(*e==' '||*e=='\t'))e--;return(e>=tc&&*e=='-')?1:0;}
int ce(const void*a,const void*b){return strcmp(*(const char**)a,*(const char**)b);}
void prc(char*cmd){int sa=0,lf=0,ip=0;char path[1024]=".";if(ciced(cmd))ip=1;char*t=strtok(cmd," ");t=strtok(NULL," ");while(t){if(t[0]=='-'){for(int i=1;t[i];i++){if(t[i]=='a')sa=1;if(t[i]=='l')lf=1;}}else strncpy(path,t,1024);t=strtok(NULL," ");}if(strcmp(path,"~")==0)strncpy(path,home_dir,1024);if(ip)strncpy(path,previous_dir,1024);DIR*d=opendir(path);if(!d){perror("opendir");return;}struct dirent*e;struct stat st;char fp[2048];char*entries[1024];int ec=0;while((e=readdir(d))!=NULL){if(!sa&&e->d_name[0]=='.')continue;entries[ec]=strdup(e->d_name);ec++;}closedir(d);qsort(entries,ec,sizeof(char*),ce);for(int i=0;i<ec;i++){snprintf(fp,sizeof(fp),"%s/%s",path,entries[i]);if(stat(fp,&st)==-1){free(entries[i]);continue;}if(S_ISDIR(st.st_mode))printf("\033[1;34m%s\033[0m",entries[i]);else if(st.st_mode&S_IXUSR)printf("\033[1;32m%s\033[0m",entries[i]);else printf("\033[1;37m%s\033[0m",entries[i]);if(lf)printf("  Size: %lld",(long long)st.st_size);printf("\n");free(entries[i]);}}
